            //
            aOrbiterF = ((aOrbiterF + aOrbiterB) + 0xBED4EB706364440BULL) + aPhaseAOrbiterUpdateSaltE[((aIndex + 9U)) & S_SALT1];
            aOrbiterA = ((aOrbiterA ^ aOrbiterF) ^ 0x852BDE6AB186E06EULL) ^ aPhaseAOrbiterUpdateSaltB[((aIndex + 26U)) & S_SALT1];
