        //
        // Ingress:
        //      aWaterLaneC (-->), aFireLaneC (-->), aOperationLaneC (-->), aKeyRowReadB (<-?->)
        //
        // Cross:
        //      aFireLaneA (<--), aFireLaneD (<--), aOperationLaneA (<-?->)
        //
        // Destination:
        //      aWaterLaneD
