            aOrbiterE = (aOrbiterE + aOrbiterD) + 0x46E1F237A4684D9FULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterE) ^ 0x5D1644E1C05137A4ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x0622ABDF061B2B2BULL), 39U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterK) + 0xDF5AD034097D9DA5ULL;
