            //
            aOrbiterD = ((aOrbiterD + aOrbiterG) + 0x6A8C5BBD3ACE3E22ULL) + aPhaseFOrbiterUpdateSaltD[((aIndex + 27U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterD) ^ 0x47A6B5B70CF96F3DULL;
            aOrbiterB = RotL64((aOrbiterB * 0x291E2BAF244F6BBDULL), 5U);
