            aWandererE = aWandererE ^ ((RotL64(aCross, 53U) + aOrbiterF) + RotL64(aOrbiterK, 23U));
            aWandererD = aWandererD + ((RotL64(aScatter, 13U) + RotL64(aOrbiterA, 47U)) + aOrbiterB);
