            //
            aOrbiterH = ((aOrbiterH + aOrbiterI) + 0xA9DFB6D27D320F71ULL) + aPhaseGOrbiterUpdateSaltE[((aIndex + 29U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterH) ^ 0x3C8EA6D9744611C9ULL;
