            //
            aOrbiterD = (aOrbiterD + aOrbiterA) + 0x53AF8BD270D162C8ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterD) ^ 0xFD4B1D9CEA9596C6ULL;
            aOrbiterH = RotL64((aOrbiterH * 0xB084A993A7360BC1ULL), 21U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterE) + 0x9D70456224DA95E1ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterK) ^ 0x84FE23972845C17EULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x8EDEF7A0ABA87EA7ULL), 53U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterK) + 0xB7F495455A0D431AULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterA) ^ 0x4AA872D2F2811269ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x8B2B9B725C726481ULL), 51U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 0x49260F12D461696AULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterJ) ^ 0x0F420D8776FB2E9DULL;
            aOrbiterG = RotL64((aOrbiterG * 0x56EC86F380B9464DULL), 3U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterB) + 0x7993A3722C1C550DULL;
