            aOrbiterK = ((aOrbiterK ^ aOrbiterB) ^ 0xFE0F105C09D8E9A8ULL) ^ aPhaseGOrbiterUpdateSaltD[(((31U - aIndex) + 27U)) & S_SALT1];
