            //
            aWandererB = aWandererB ^ ((RotL64(aPrevious, 27U) + aOrbiterG) + RotL64(aOrbiterE, 3U));
            aWandererH = aWandererH + (((RotL64(aCross, 24U) + aOrbiterD) + RotL64(aOrbiterF, 27U)) + RotL64(aCarry, 53U));
