            aOrbiterG = (((aWandererF + RotL64(aPrevious, 35U)) + RotL64(aCarry, 37U)) + 0xA04EAA28CFB0B279ULL) + aPhaseHOrbiterAssignSaltE[(((31U - aIndex) + 14U)) & S_SALT1];
